import anthropic, os

# Factory pattern: pick the right client based on data classification
def get_claude_client(data_classification: str):
    if data_classification == "public":
        # Direct API: fastest setup, no residency constraint
        return anthropic.Anthropic(
            api_key=os.environ["ANTHROPIC_API_KEY"]
        ), "claude-opus-4-8"

    elif data_classification == "internal":
        # Bedrock US: data stays in AWS US; SOC 2 compliant
        return anthropic.AnthropicBedrock(
            aws_region="us-east-1"
        ), "anthropic.claude-opus-4-8"

    elif data_classification == "eu-pii":
        # Vertex AI EU: data stays in EU; GDPR compliant
        return anthropic.AnthropicVertex(
            region="europe-west4",
            project_id=os.environ["GCP_PROJECT_ID"],
        ), "claude-opus-4-8@20251101"

    else:
        raise ValueError(f"Unknown classification: {data_classification}")

# Use it
client, model = get_claude_client("eu-pii")
response = client.messages.create(
    model=model,
    max_tokens=512,
    messages=[{"role": "user", "content": "Summarize this EU customer complaint..."}],
)
